from math import comb
def check(d,o,n,count=False): # checks that the d-dimensional simplex numbers form a basis of order o for the naturals <= n.
    m=~(~0<<n+1)
    a=1
    for i in range(o):
        b=a
        k=d
        while (s:=comb(k,d))<=n:
            b|=a<<s
            k+=1
        a=b&m
    E=[];e=m&~a
    if count: return (e.bit_count(),e.bit_length()-1) # number of exceptions and maximum
    while e: d=e&-e;E.append(d.bit_length()-1);e&=~d # extract terms; this loop is slow
    return E # exceptions
